                    sprintf(
                        'Error JSON decoding server response (%s)',
                        $request->getUri()
                    ),
                    $exception->getCode(),
                    $response,
                    $exception
                );
            }
        }

        return [
            ObjectSerializer::deserialize($content, $dataType),
            $response,
        ];
    }
}
